const record = $input.first().json.record;
return [{
  json: {
    title: `Review Required: ${record.title}`,
    description: `Content type: ${record.content_type}\nChannel: ${record.channel || 'N/A'}\nURL: ${record.content_url || 'Not provided'}\n\nSubmitted for Ewa's compliance review before publishing.`,
    contentReviewId: record.id,
    contentTitle: record.title,
    contentUrl: record.content_url
  }
}];
